import json, re

with open('/workspace/segments.json') as f:
    segs = json.load(f)

print('=== Schema Validation ===')
errors = []
for i, s in enumerate(segs):
    if not isinstance(s['start'], (int, float)):
        errors.append(f'seg[{i}]: start not a number')
    if not isinstance(s['end'], (int, float)):
        errors.append(f'seg[{i}]: end not a number')
    if s['start'] >= s['end']:
        errors.append(f'seg[{i}]: start >= end ({s[\"start\"]} >= {s[\"end\"]})')
    if not isinstance(s['label'], str) or not re.match(r'^[A-Z]$', s['label']):
        errors.append(f'seg[{i}]: label not a single uppercase letter: {s[\"label\"]}')

# Sorted by start
for i in range(1, len(segs)):
    if segs[i]['start'] < segs[i-1]['start']:
        errors.append(f'segments not sorted by start')

# Coverage: start near 0, end near duration
if segs[0]['start'] > 0.5:
    errors.append(f'first segment starts at {segs[0][\"start\"]} (> 0.5)')

# No significant gaps or overlaps
for i in range(len(segs) - 1):
    gap = segs[i+1]['start'] - segs[i]['end']
    if abs(gap) > 0.5:
        errors.append(f'gap/overlap of {gap:.3f}s between seg[{i}] and seg[{i+1}]')

# At least 2 distinct labels
labels = set(s['label'] for s in segs)
if len(labels) < 2:
    errors.append(f'only {len(labels)} distinct labels')

# At least 3 segments
if len(segs) < 3:
    errors.append(f'only {len(segs)} segments')

# Every segment > 0.5s
for i, s in enumerate(segs):
    if s['end'] - s['start'] <= 0.5:
        errors.append(f'seg[{i}] duration {s[\"end\"]-s[\"start\"]:.3f}s <= 0.5s')

# At least one label re-used
from collections import Counter
cnt = Counter(s['label'] for s in segs)
reused = [l for l, c in cnt.items() if c > 1]
if not reused:
    errors.append('no label is re-used')

if errors:
    print('FAILED:')
    for e in errors:
        print(f'  - {e}')
else:
    print('ALL CHECKS PASSED')
    print(f'  Segments: {len(segs)}')
    print(f'  Labels: {labels}')
    print(f'  Reused: {reused}')
    for s in segs:
        print(f'  {s[\"start\"]:7.2f}s -> {s[\"end\"]:7.2f}s [{s[\"label\"]}] ({s[\"end\"]-s[\"start\"]:.2f}s)')
